#include <bits/stdc++.h>
using namespace std;
string A,B,a[1005],b[1005];
int n;
struct node {
    string s;
    int step;
};
queue<node>q;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>A>>B;
	while(cin>>a[n]>>b[n])
		n++;
	q.push({A,0});
	while(q.size()) {
		node t=q.front();
		q.pop();
		if(t.step==10) 
			continue;
		for(int i=0; i<n; i++) {
			int pos=t.s.find(a[i]);
			while(pos!=-1) {
				string ns=t.s;
				ns.replace(pos,a[i].size(),b[i]);
				if(ns==B) {
					cout<<t.step+1;
					return 0;
				}
				q.push({ns,t.step+1});
				pos=t.s.find(a[i],pos+1);
			}
		}
	}
	cout<<"NO ANSWER!";
	return 0;
}
